'use strict';

const NEW_SITE_HTML_URL = 'https://raw.githubusercontent.com/loyality7/sarath/main/index.html';
const CSS_B64 = '';
const JS_B64  = '';

function pickNodes(html) {
  const parser = new DOMParser();
  const doc    = parser.parseFromString(html, 'text/html');
  const ids    = ['boot-screen','app','scanlines','noise-canvas','matrix-canvas','konami-flash','bg-canvas'];
  const out    = {};
  ids.forEach(id => {
    const el = doc.getElementById(id);
    if (el) out[id] = el.cloneNode(true);
  });
  return out;
}

function initSwitch() {
  const btn   = document.getElementById('switch-btn');
  const modal = document.getElementById('new-site-modal');
  if (!btn || !modal) {
    console.error('[INJECT] button or modal not found');
    return;
  }

  btn.addEventListener('click', () => {
    btn.style.display = 'none';
    modal.style.display = 'block';
    modal.style.overflowY = 'auto';
    modal.innerHTML = '<pre style="color:#00ff41;text-align:center;padding:40vh 20px;font-family:Share Tech Mono,monospace;font-size:13px;text-shadow:0 0 6px rgba(0,255,65,.5);">LOADING SARATH.OS...\n> DECODING CORE MODULES</pre>';

    (async () => {
      try {
        const cssText = atob(CSS_B64);
        const jsText  = atob(JS_B64);

        const style = document.createElement('style');
        style.textContent = cssText;
        document.head.appendChild(style);

        const r = await fetch(NEW_SITE_HTML_URL);
        if (!r.ok) throw new Error('HTML fetch failed: HTTP ' + r.status);
        const html = await r.text();
        const nodes = pickNodes(html);
        modal.innerHTML = '';
        ['boot-screen','app','scanlines','noise-canvas','matrix-canvas','konami-flash','bg-canvas'].forEach(id => {
          if (nodes[id]) modal.appendChild(nodes[id]);
        });

        const blob = new Blob([jsText], { type: 'application/javascript' });
        const url  = URL.createObjectURL(blob);
        const s    = document.createElement('script');
        s.src = url;
        await new Promise((resolve, reject) => {
          s.onload = () => { URL.revokeObjectURL(url); resolve(); };
          s.onerror = () => { URL.revokeObjectURL(url); reject(new Error('JS blob failed')); };
          document.body.appendChild(s);
        });

        modal.querySelectorAll('a[href^="#"]').forEach(a => {
          a.addEventListener('click', e => {
            e.preventDefault();
            const t = modal.querySelector(a.getAttribute('href'));
            if (t) t.scrollIntoView({ behavior: 'smooth' });
          });
        });

      } catch (err) {
        modal.innerHTML = '<pre style="color:#ff2d55;text-align:center;padding:30vh 20px;font-family:Share Tech Mono,monospace;font-size:12px;">ERROR: ' + err.message + '</pre>';
        console.error('[INJECT]', err);
      }
    })();
  });
}

initSwitch();
